#[Debug(reload: true)]
function debug_setCardType(int $id, int $type, int $typeArg = 0) {
  $this->DbQuery("UPDATE `card` SET `card_type` = $type, `card_type_arg` = $typeArg WHERE `card_id` = $id" );
}

// jump to a state, for example to simulate the end of a player turn and go to the next player turn.
public function debug_goToState(int $state = ST_NEXT_PLAYER) {
  $this->gamestate->jumpToState($state);
}

// play one move, using the zombie code
function debug_playOneMove() {
    $this->debug->playUntil(fn(int $count) => $count == 1);
}

// if you want to be able to concede
function debug_playToFiftyPercent() {
    $this->debug->playUntil(fn(int $count) => $this->gamestate->getCurrentMainStateId() >= ST_END_GAME || $this->getGameProgression() >= 50 || $count >= 100);
}

// to see end game result
function debug_playToEndGame() {
    $this->debug->playUntil(fn(int $count) => $this->gamestate->getCurrentMainStateId() >= ST_END_GAME || $count >= 100);
}

// to see end round result
function debug_playToEndRound() {
  $round = $this->getCurrentRound();
  $this->debug->playUntil(fn(int $count) => $this->getCurrentRound() > $round);
}

// to go to the turn of a specific player
function debug_playUntilTurnOf(int $playerId) {
    $this->debug->playUntil(fn(int $count) => (int)$this->getActivePlayerId() === $playerId);
}
function debug_playUntilMyTurn() {
    $this->debug->playUntil(fn(int $count) => (int)$this->getActivePlayerId() === (int)$this->getCurrentPlayerId());
}

